CREATE VIEW `dim_short_viedo_adid_info_view` (`id` COMMENT "自增id", `fb_account` COMMENT "账号id", `ad_status` COMMENT "广告状态", `ad_id` COMMENT "广告id", `ad_name` COMMENT "广告名称", `ad_set_id` COMMENT "广告组id", `ad_camp_id` COMMENT "广告系列id")
COMMENT "海外短剧广告投放信息，广告id等" AS (SELECT `ods`.`ods_tidb_sharpengine_ads_global_ThirdAd`.`id`, `ods`.`ods_tidb_sharpengine_ads_global_ThirdAd`.`fbaccount` AS `fb_account`, `ods`.`ods_tidb_sharpengine_ads_global_ThirdAd`.`adstatus` AS `ad_status`, `ods`.`ods_tidb_sharpengine_ads_global_ThirdAd`.`adid` AS `ad_id`, `ods`.`ods_tidb_sharpengine_ads_global_ThirdAd`.`adname` AS `ad_name`, `ods`.`ods_tidb_sharpengine_ads_global_ThirdAd`.`adsetid` AS `ad_set_id`, `ods`.`ods_tidb_sharpengine_ads_global_ThirdAd`.`adcampid` AS `ad_camp_id`
FROM `ods`.`ods_tidb_sharpengine_ads_global_ThirdAd` UNION ALL SELECT `ods`.`ods_tidb_sharpengine_ads_global_TiktokAd`.`id`, `ods`.`ods_tidb_sharpengine_ads_global_TiktokAd`.`fbaccount` AS `fb_account`, `ods`.`ods_tidb_sharpengine_ads_global_TiktokAd`.`adstatus` AS `ad_status`, `ods`.`ods_tidb_sharpengine_ads_global_TiktokAd`.`adid` AS `ad_id`, `ods`.`ods_tidb_sharpengine_ads_global_TiktokAd`.`adname` AS `ad_name`, `ods`.`ods_tidb_sharpengine_ads_global_TiktokAd`.`adsetid` AS `ad_set_id`, `ods`.`ods_tidb_sharpengine_ads_global_TiktokAd`.`adcampid` AS `ad_camp_id`
FROM `ods`.`ods_tidb_sharpengine_ads_global_TiktokAd`);
